INSERT INTO `project` (`id`, `sponsor_id`, `category_id`, `title`, `summary`, `cover_image`, `content`, `target_amount`, `current_amount`, `supporter_count`, `end_time`, `status`, `heat`) VALUES 
(1001, 1, 2, '乡村儿童图书馆建设计划', '为贫困山区的孩子们建设10所乡村儿童图书馆，提供丰富的阅读资源。', 'https://images.unsplash.com/photo-1481627834876-b7833e8f5570?auto=format&fit=crop&q=80&w=800', '<p>知识改变命运。我们将为10所偏远地区小学建立爱心图书馆，购买适合儿童阅读的图书10万册。</p>', 100000.00, 25000.00, 150, '2026-12-31 23:59:59', 1, 5000),
(1002, 1, 2, '西部留守老人暖冬行动', '为西部的留守老人提供过冬棉衣和基本的生活物资，让他们度过一个温暖的冬天。', 'https://images.unsplash.com/photo-1542884748-2b87b36c6b90?auto=format&fit=crop&q=80&w=800', '<p>西部高寒地区，许多留守老人缺乏御寒物资。本项目计划为500位老人提供包含棉被、保暖内衣等在内的暖冬物资包。</p>', 50000.00, 48000.00, 400, '2026-11-30 23:59:59', 1, 8000),
(1003, 1, 2, '助残就业手工艺品培训', '为残障人士提供专业的手工艺品制作培训，帮助他们获得一技之长，实现自力更生。', 'https://images.unsplash.com/photo-1459180129673-eefb56f79b45?auto=format&fit=crop&q=80&w=800', '<p>通过为期3个月的培训，让残疾人掌握非遗手工编织技术，并协助他们销售手工艺品。</p>', 80000.00, 10000.00, 50, '2026-10-15 23:59:59', 1, 3000),
(1004, 1, 2, '流浪动物救助站改造项目', '为当地的流浪动物救助站进行基础设施升级，改善流浪猫狗的生存环境。', 'https://images.unsplash.com/photo-1548767797-d8c844163c4c?auto=format&fit=crop&q=80&w=800', '<p>救助站年久失修，每逢雨季就会漏水。我们将对其进行全面翻修，加固犬舍，添置保暖设备和医疗器械。</p>', 30000.00, 30000.00, 600, '2026-08-01 23:59:59', 5, 9500),
(1005, 1, 2, '海洋生态环境保护行动', '组织志愿者进行海滩垃圾清理，并在沿海社区开展海洋保护知识宣讲。', 'https://images.unsplash.com/photo-1484291470158-b8f8d608850d?auto=format&fit=crop&q=80&w=800', '<p>海洋污染日益严重。本项目将在10个海滩开展清理活动，并举办50场海洋保护讲座。</p>', 60000.00, 12000.00, 80, '2026-09-30 23:59:59', 1, 4000);
